import React, { useState } from 'react';

const Gallery = () => {
  const [activeFilter, setActiveFilter] = useState('all');
  const [lightboxOpen, setLightboxOpen] = useState(false);

  const filters = [
    { id: 'all', label: 'All Work' },
    { id: 'bridal', label: 'Bridal Makeup' },
    { id: 'hair', label: 'Hair Styling' },
    { id: 'wedding', label: 'Wedding Moments' },
    { id: 'transformations', label: 'Salon Transformations' },
    { id: 'treatments', label: 'Beauty Treatments' }
  ];

  const galleryItems = [
    { id: 1, category: 'bridal', src: '/images/gallery/image7.jpg', alt: 'Bridal Makeup 1' },
    { id: 2, category: 'hair', src: '/images/gallery/image8.jpg', alt: 'Hair Styling 1' },
    { id: 3, category: 'wedding', src: '/images/gallery/image9.jpg', alt: 'Wedding Moment 1' }
  ];

  const openLightbox = () => {
    setLightboxOpen(true);
  };

  const closeLightbox = () => {
    setLightboxOpen(false);
  };

  const filteredItems = activeFilter === 'all' 
    ? galleryItems 
    : galleryItems.filter(item => item.category === activeFilter);

  return (
    <section className="gallery" id="gallery">
      <div className="container">
        <div className="section-head reveal">
          <div className="eyebrow">Bridal Gallery</div>
          <h2>Our Bridal Transformations</h2>
          <p>Premium masonry gallery showcasing our beautiful bridal work.</p>
        </div>

        <div className="gallery-filters">
          {filters.map(filter => (
            <button
              key={filter.id}
              className={`filter-btn ${activeFilter === filter.id ? 'active' : ''}`}
              onClick={() => setActiveFilter(filter.id)}
            >
              {filter.label}
            </button>
          ))}
        </div>

        <div className="masonry">
          {filteredItems.map(item => (
            <div
              key={item.id}
              className="masonry-item"
              onClick={openLightbox}
            >
              <img src={item.src} alt={item.alt} />
              <div className="zoom-icon">
                <i className="fa-solid fa-magnifying-glass-plus"></i>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Lightbox */}
      <div className={`lightbox ${lightboxOpen ? 'open' : ''}`} onClick={closeLightbox}>
        <div className="lightbox-inner" onClick={(e) => e.stopPropagation()}>
          <div className="img-ph" style={{ height: '100%' }}>
            <div className="ph-label">
              <i className="fa-solid fa-image"></i>
              <span>Gallery Image</span>
            </div>
          </div>
        </div>
        <button className="lightbox-close" onClick={closeLightbox}>
          <i className="fa-solid fa-times"></i>
        </button>
      </div>
    </section>
  );
};

export default Gallery;
